const sources = [
  { name: 'Google News', node: 'Fetch Google News' },
  { name: 'TechCrunch AI', node: 'Fetch TechCrunch AI' },
];
function strip(s) {
  if (!s) return '';
  s = String(s);
  s = s.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1');
  s = s.replace(/<[^>]+>/g, ' ');
  s = s.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
  s = s.replace(/&#39;/g, "'").replace(/&#x27;/g, "'").replace(/&amp;/g, '&');
  s = s.replace(/\s+/g, ' ').trim();
  return s;
}
function pick(block, tag) {
  const re = new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)</' + tag + '>', 'i');
  const m = block.match(re);
  return m ? m[1] : '';
}
const all = [];
for (const src of sources) {
  let xml = '';
  try {
    const j = $(src.node).first().json;
    xml = j.data || j.body || '';
  } catch (e) { xml = ''; }
  if (!xml || typeof xml !== 'string') continue;
  const parts = xml.split(/<item[\s>]/i).slice(1);
  for (const raw of parts) {
    try {
      const block = '<item ' + raw;
      const title = strip(pick(block, 'title'));
      let link = strip(pick(block, 'link'));
      if (!link) {
        const m = block.match(/<link[^>]*href="([^"]+)"/i);
        if (m) link = m[1];
      }
      const desc = strip(pick(block, 'description')) || strip(pick(block, 'summary'));
      const pub = strip(pick(block, 'pubDate')) || strip(pick(block, 'updated')) || strip(pick(block, 'published'));
      if (!title) continue;
      all.push({ title: title, url: link, description: desc, pubDate: pub, source: src.name });
    } catch (e) { continue; }
  }
}
return [{ json: { articles: all, fetchedCount: all.length } }];

const LF = String.fromCharCode(10);
const data = $input.first() ? $input.first().json : {};
const articles = Array.isArray(data.articles) ? data.articles : [];
const now = Date.now();
const sevenDays = 7 * 24 * 60 * 60 * 1000;
const oneDay = 24 * 60 * 60 * 1000;
// Whole-word / regex keyword matching so 'ai' does NOT match email, said, chair, retail.
const KEYWORDS = ['ai','artificial intelligence','generative ai','generative','genai','llm','large language model','agent','agents','ai agent','automation','openai','anthropic','claude','gemini','copilot','n8n','zapier','make.com','machine learning','chatgpt','neural network','deepmind'];
function esc(s) { return s.replace(/\./g, '\\.'); }
const KW_RE = KEYWORDS.map(function (k) { return new RegExp('\\b' + esc(k) + '\\b', 'i'); });
function relevant(a) {
  const t = (a.title || '') + ' ' + (a.description || '');
  return KW_RE.some(function (re) { return re.test(t); });
}
function norm(s) { return (s || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').replace(/\s+/g, ' ').trim(); }
// Strict date parsing: reject missing and invalid dates.
function parseDate(s) {
  if (!s || typeof s !== 'string' || !s.trim()) return null;
  const d = new Date(s);
  const ms = d.getTime();
  return isNaN(ms) ? null : ms;
}
const recent = [];
for (const a of articles) {
  if (!relevant(a)) continue;
  const t = parseDate(a.pubDate);
  if (t === null) continue;               // reject missing / invalid dates
  if ((now - t) > sevenDays) continue;    // reject older than 7 days
  if ((t - now) > oneDay) continue;       // reject more than 1 day in the future
  a._ts = t;
  recent.push(a);
}
// Deduplicate near-identical titles.
function sig(s) { return s.split(' ').filter(function (w) { return w.length > 3; }); }
function similar(a, b) {
  if (a === b) return true;
  const wa = sig(a);
  const wb = sig(b);
  if (!wa.length || !wb.length) return false;
  let common = 0;
  for (const w of wa) { if (wb.indexOf(w) !== -1) common++; }
  return (common / Math.min(wa.length, wb.length)) >= 0.7;
}
const seen = [];
const deduped = [];
for (const a of recent) {
  const n = norm(a.title);
  let dup = false;
  for (const s of seen) { if (similar(n, s)) { dup = true; break; } }
  if (dup) continue;
  seen.push(n);
  deduped.push(a);
}
deduped.sort(function (x, y) { return y._ts - x._ts; });
const limited = deduped.slice(0, 15);   // limit to 15 articles
function fmt(ms) { return new Date(ms).toISOString().slice(0, 10); }
let text = '';
limited.forEach(function (a, i) {
  text += (i + 1) + '. ' + a.title + LF;
  text += 'Source: ' + a.source + LF;
  text += 'URL: ' + (a.url || 'N/A') + LF;
  text += 'Date: ' + (a.pubDate || 'Unknown') + LF;
  if (a.description) text += 'Summary: ' + a.description.slice(0, 400) + LF;
  text += LF;
});
return [{ json: {
  hasArticles: limited.length > 0,
  count: limited.length,
  periodStart: fmt(now - sevenDays),
  periodEnd: fmt(now),
  articles: limited,
  articlesText: text
} }];

