const LF = String.fromCharCode(10);

/**
 * Read AI response safely.
 */
let ai = '';

try {
  const result = $('Summarize with AI').first().json;

  ai =
    result.output?.[0]?.content?.[0]?.text ||
    result.output_text ||
    result.text ||
    result.response ||
    result.message?.content ||
    result.content ||
    '';
} catch (error) {
  ai = '';
}

/**
 * Read filtered article data.
 */
const f = $('Filter, Dedupe & Prepare').first().json || {};

const articles = Array.isArray(f.articles)
  ? f.articles
  : [];

if (!ai || ai.trim().length < 20) {
  ai =
    '## Executive Summary' +
    LF +
    'The AI summary could not be generated this week. Please review the sources below.' +
    LF;
}

/**
 * Build the main Markdown digest.
 */
let md = '';

md +=
  '# Weekly AI & Automation Competitor Digest' +
  LF +
  LF;

md +=
  '**Reporting period:** ' +
  (f.periodStart || 'Unknown') +
  ' – ' +
  (f.periodEnd || 'Unknown') +
  LF +
  LF;

md += ai.trim() + LF + LF;

md += '## Sources Reviewed' + LF + LF;

if (articles.length === 0) {
  md += '* No source articles were available.' + LF;
} else {
  articles.forEach(function (article) {
    const title = article.title || 'Untitled';
    const url = article.url || article.link || '';
    const source = article.source || 'Unknown';

    if (url) {
      md +=
        '* [' +
        title +
        '](' +
        url +
        ') — ' +
        source +
        LF;
    } else {
      md +=
        '* ' +
        title +
        ' — ' +
        source +
        LF;
    }
  });
}

/**
 * Convert Markdown into Gmail HTML.
 */
function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function inlineHtml(value) {
  let output = escapeHtml(value);

  output = output.replace(
    /\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g,
    '<a href="$2" target="_blank" style="color:#2563eb;text-decoration:none;">$1</a>'
  );

  output = output.replace(
    /\*\*([^*]+)\*\*/g,
    '<strong>$1</strong>'
  );

  return output;
}

const lines = md.split(/\r?\n/);

let html = '';
let listType = null;

function closeList() {
  if (listType) {
    html += '</' + listType + '>';
    listType = null;
  }
}

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();

  if (!line) {
    closeList();
    continue;
  }

  if (line.startsWith('### ')) {
    closeList();

    html +=
      '<h3 style="margin:16px 0 6px;font-size:16px;color:#111;">' +
      inlineHtml(line.slice(4)) +
      '</h3>';

    continue;
  }

  if (line.startsWith('## ')) {
    closeList();

    html +=
      '<h2 style="margin:22px 0 8px;font-size:20px;color:#111;border-bottom:1px solid #eeeeee;padding-bottom:4px;">' +
      inlineHtml(line.slice(3)) +
      '</h2>';

    continue;
  }

  if (line.startsWith('# ')) {
    closeList();

    html +=
      '<h1 style="margin:0 0 12px;font-size:26px;color:#111;">' +
      inlineHtml(line.slice(2)) +
      '</h1>';

    continue;
  }

  if (line.startsWith('* ') || line.startsWith('- ')) {
    if (listType !== 'ul') {
      closeList();

      html +=
        '<ul style="margin:6px 0 12px 20px;padding:0;">';

      listType = 'ul';
    }

    html +=
      '<li style="margin:5px 0;">' +
      inlineHtml(line.slice(2)) +
      '</li>';

    continue;
  }

  const orderedMatch = line.match(/^\d+\.\s+(.*)$/);

  if (orderedMatch) {
    if (listType !== 'ol') {
      closeList();

      html +=
        '<ol style="margin:6px 0 12px 20px;padding:0;">';

      listType = 'ol';
    }

    html +=
      '<li style="margin:5px 0;">' +
      inlineHtml(orderedMatch[1]) +
      '</li>';

    continue;
  }

  closeList();

  html +=
    '<p style="margin:8px 0;">' +
    inlineHtml(line) +
    '</p>';
}

closeList();

const digestHtml =
  '<div style="font-family:Arial,Helvetica,sans-serif;color:#222;line-height:1.5;max-width:680px;margin:0 auto;">' +
  html +
  '</div>';

/**
 * Convert Markdown into Slack mrkdwn.
 */
function markdownToSlack(markdown) {
  return String(markdown || '')
    // Markdown link → Slack link
    .replace(
      /\[([^\]]+)\]\((https?:\/\/[^)\s]+)\)/g,
      '<$2|$1>'
    )

    // Headings → Slack bold
    .replace(/^###\s+(.+)$/gm, '*$1*')
    .replace(/^##\s+(.+)$/gm, '*$1*')
    .replace(/^#\s+(.+)$/gm, '*$1*')

    // Markdown bold → Slack bold
    .replace(
      /\*\*([^*]+)\*\*/g,
      '*$1*'
    )

    // Markdown bullets → Slack bullets
    .replace(/^[-*]\s+/gm, '• ')

    // Remove excessive blank lines
    .replace(/\n{3,}/g, '\n\n')

    .trim();
}

const digestSlack = markdownToSlack(md);

/**
 * Output values for Gmail and Slack.
 */
return [
  {
    json: {
      digestMarkdown: md,
      digestHtml: digestHtml,
      digestSlack: digestSlack,
      subject:
        'Weekly AI & Automation Digest — ' +
        (f.periodEnd || new Date().toISOString().slice(0, 10)),
      count: f.count || articles.length
    }
  }
];
